import React, { useEffect, useRef, useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";

// ── Icons ──────────────────────────────────────────────
const HomeIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
    <path d="M3 12L12 3l9 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M5 10v11h14V10" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M9 21V12h6v9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

const RetryIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
    <path d="M3 12a9 9 0 1 0 9-9 9 9 0 0 0-6.36 2.64L3 8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
    <path d="M3 3v5h5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

// ── Particle canvas for hero banner ───────────────────
function ParticleBanner({ granted }) {
  const canvasRef = useRef(null);
  const color = granted ? "#06d6a0" : "#f72585";

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;

    const particles = Array.from({ length: 55 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      r: Math.random() * 2 + 0.5,
      dx: (Math.random() - 0.5) * 0.4,
      dy: (Math.random() - 0.5) * 0.4,
      o: Math.random() * 0.5 + 0.1,
    }));

    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p) => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = color + Math.floor(p.o * 255).toString(16).padStart(2, "0");
        ctx.fill();
        p.x += p.dx;
        p.y += p.dy;
        if (p.x < 0 || p.x > canvas.width) p.dx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.dy *= -1;
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(raf);
  }, [color]);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: "absolute", inset: 0,
        width: "100%", height: "100%",
        borderRadius: "inherit", pointerEvents: "none",
      }}
    />
  );
}

// ── Security Score Ring ────────────────────────────────
function ScoreRing({ score, granted }) {
  const [animated, setAnimated] = useState(0);
  const radius = 54;
  const stroke = 7;
  const circ = 2 * Math.PI * radius;
  const color = granted ? "#06d6a0" : score > 40 ? "#ffd166" : "#f72585";

  useEffect(() => {
    let start = null;
    const duration = 1200;
    const target = Math.min(100, Math.max(0, score));
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      const ease = 1 - Math.pow(1 - p, 3);
      setAnimated(ease * target);
      if (p < 1) requestAnimationFrame(step);
    };
    const t = setTimeout(() => requestAnimationFrame(step), 300);
    return () => clearTimeout(t);
  }, [score]);

  const offset = circ - (animated / 100) * circ;

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
      <svg width={130} height={130} viewBox="0 0 130 130">
        {/* Track */}
        <circle cx="65" cy="65" r={radius} fill="none"
          stroke="rgba(255,255,255,0.06)" strokeWidth={stroke} />
        {/* Fill */}
        <circle cx="65" cy="65" r={radius} fill="none"
          stroke={color} strokeWidth={stroke}
          strokeDasharray={circ} strokeDashoffset={offset}
          strokeLinecap="round"
          transform="rotate(-90 65 65)"
          style={{ transition: "none", filter: `drop-shadow(0 0 6px ${color}66)` }}
        />
        <text x="65" y="60" textAnchor="middle"
          style={{ fill: color, fontSize: 22, fontWeight: 700, fontFamily: "var(--font-display)" }}>
          {Math.round(animated)}
        </text>
        <text x="65" y="76" textAnchor="middle"
          style={{ fill: "var(--text-muted)", fontSize: 10, fontFamily: "var(--font-body)" }}>
          SCORE
        </text>
      </svg>
      <span style={{ fontSize: "0.72rem", color: "var(--text-secondary)", letterSpacing: "0.08em", textTransform: "uppercase" }}>
        Security Score
      </span>
    </div>
  );
}

// ── Confidence Meter ───────────────────────────────────
function ConfidenceMeter({ label, value, colorStart, colorEnd, delay = 0 }) {
  const [width, setWidth] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => setWidth(Math.min(100, Math.max(0, value))), 500 + delay);
    return () => clearTimeout(t);
  }, [value, delay]);

  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6, fontSize: "0.83rem" }}>
        <span style={{ color: "var(--text-secondary)" }}>{label}</span>
        <span style={{ fontWeight: 600, color: "#fff" }}>{value?.toFixed(1)}%</span>
      </div>
      <div style={{
        width: "100%", height: 6, background: "var(--bg-secondary)",
        borderRadius: 99, overflow: "hidden",
      }}>
        <div style={{
          height: "100%", borderRadius: 99,
          width: `${width}%`,
          background: `linear-gradient(90deg, ${colorStart}, ${colorEnd})`,
          transition: "width 1s cubic-bezier(0.4,0,0.2,1)",
          boxShadow: `0 0 8px ${colorEnd}66`,
        }} />
      </div>
    </div>
  );
}

// ── Auth Timeline ──────────────────────────────────────
function AuthTimeline({ granted, isFake }) {
  const steps = [
    {
      label: "Voice Received",
      desc: "Audio captured and preprocessed",
      done: true,
      color: "#4361ee",
    },
    {
      label: "Speaker Verification",
      desc: "ECAPA-TDNN embedding comparison",
      done: true,
      color: granted || !isFake ? "#4361ee" : "#f72585",
    },
    {
      label: "Deepfake Detection",
      desc: "AASIST anti-spoofing analysis",
      done: true,
      color: isFake ? "#f72585" : "#4361ee",
    },
    {
      label: "Decision",
      desc: granted ? "Access granted" : "Access denied",
      done: true,
      color: granted ? "#06d6a0" : "#f72585",
    },
  ];

  return (
    <div style={{ padding: "4px 0" }}>
      {steps.map((step, i) => (
        <div key={i} style={{ display: "flex", gap: 14, marginBottom: i < steps.length - 1 ? 0 : 0 }}>
          {/* Line + dot column */}
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", flexShrink: 0 }}>
            <div style={{
              width: 28, height: 28, borderRadius: "50%",
              background: step.color + "22",
              border: `2px solid ${step.color}`,
              display: "flex", alignItems: "center", justifyContent: "center",
              flexShrink: 0,
              animation: "fadeInUp 0.4s ease both",
              animationDelay: `${i * 0.12}s`,
            }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none">
                <path d="M5 12l5 5L19 7" stroke={step.color} strokeWidth="2.5"
                  strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </div>
            {i < steps.length - 1 && (
              <div style={{
                width: 1, flexGrow: 1, minHeight: 24,
                background: `linear-gradient(to bottom, ${step.color}44, ${steps[i + 1].color}22)`,
                margin: "3px 0",
              }} />
            )}
          </div>
          {/* Text */}
          <div style={{
            paddingBottom: i < steps.length - 1 ? 18 : 0,
            animation: "fadeInUp 0.4s ease both",
            animationDelay: `${i * 0.12 + 0.05}s`,
          }}>
            <div style={{ fontSize: "0.88rem", fontWeight: 600, color: "#fff", marginBottom: 2 }}>
              {step.label}
            </div>
            <div style={{ fontSize: "0.76rem", color: "var(--text-muted)" }}>{step.desc}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

// ── Hero Banner ────────────────────────────────────────
function HeroBanner({ granted, isFake, status, reason, score }) {
  const color = granted ? "#06d6a0" : isFake ? "#f72585" : "#ffd166";
  const bgColor = granted ? "rgba(6,214,160,0.07)" : isFake ? "rgba(247,37,133,0.07)" : "rgba(255,209,102,0.07)";
  const label = granted ? "ACCESS GRANTED" : isFake ? "SPOOFING DETECTED" : "ACCESS DENIED";

  return (
    <div style={{
      position: "relative", overflow: "hidden",
      background: bgColor,
      border: `1px solid ${color}33`,
      borderLeft: `4px solid ${color}`,
      borderRadius: "var(--r-xl)",
      padding: "clamp(24px, 4vw, 36px)",
      display: "flex", alignItems: "center",
      justifyContent: "space-between", flexWrap: "wrap", gap: 24,
      boxShadow: `0 8px 32px ${color}18`,
    }}>
      <ParticleBanner granted={granted} />

      {/* Left: status */}
      <div style={{ position: "relative", zIndex: 1 }}>
        <div style={{
          display: "inline-flex", alignItems: "center", gap: 8,
          background: color + "22", border: `1px solid ${color}44`,
          borderRadius: 99, padding: "4px 14px", marginBottom: 12,
        }}>
          <span style={{
            width: 7, height: 7, borderRadius: "50%",
            background: color, boxShadow: `0 0 8px ${color}`,
            display: "inline-block", flexShrink: 0,
          }} />
          <span style={{ fontSize: "0.7rem", fontWeight: 700, color, letterSpacing: "0.1em" }}>
            {label}
          </span>
        </div>
        <h2 style={{
          fontFamily: "var(--font-display)", fontSize: "clamp(1.4rem, 3vw, 1.9rem)",
          fontWeight: 700, color, marginBottom: 6, lineHeight: 1.15,
        }}>
          {status}
        </h2>
        {reason && (
          <p style={{ color: "var(--text-secondary)", fontSize: "0.86rem", maxWidth: 420 }}>{reason}</p>
        )}
      </div>

      {/* Right: ring */}
      <div style={{ position: "relative", zIndex: 1 }}>
        <ScoreRing score={score} granted={granted} />
      </div>
    </div>
  );
}

// ── Main Result Page ───────────────────────────────────
export default function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const data = location.state?.data;

  if (!data) {
    return (
      <div className="auth-page">
        <div className="auth-container" style={{ textAlign: "center" }}>
          <p style={{ color: "var(--text-secondary)", marginBottom: 20 }}>
            No authentication result found.
          </p>
          <button className="btn btn-primary" onClick={() => navigate("/login")}>
            Go to Login
          </button>
        </div>
      </div>
    );
  }

  const isGranted = data.access === "Granted";
  const isFake = data.status?.toLowerCase().includes("fake");
  const securityScore = isGranted
    ? Math.round((data.similarity + data.real_prob) / 2)
    : Math.round((data.fake_prob + (100 - data.similarity)) / 2);

  return (
    <div className="result-page">
      <CyberBackground />

      <div className="orb orb-blue" />
      <div className="orb orb-purple" />

      <div className="result-container" style={{ maxWidth: 860 }}>

        {/* Top actions */}
        <div className="result-actions-top">
          <button className="btn btn-ghost" onClick={() => navigate("/")}>
            <HomeIcon /> Home
          </button>
          <button className="btn btn-ghost" onClick={() => navigate("/login")}>
            <RetryIcon /> Try Again
          </button>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>

          {/* 1. Animated Hero Banner + Score Ring */}
          <HeroBanner
            granted={isGranted}
            isFake={isFake}
            status={data.status}
            reason={data.reason}
            score={securityScore}
          />

          {/* 2. Stats row */}
          <div className="stats-row">
            {[
              { label: "Similarity", value: data.similarity, color: "var(--cyan)" },
              { label: "Real Prob.", value: data.real_prob, color: "var(--green)" },
              { label: "Fake Prob.", value: data.fake_prob, color: "var(--pink)" },
              ...(data.distance != null ? [{ label: "Distance", value: data.distance, color: "var(--yellow)", raw: true }] : []),
            ].map((s) => (
              <div className="stat-card" key={s.label}>
                <div className="stat-value" style={{ color: s.color }}>
                  {s.raw ? s.value : `${s.value?.toFixed(1)}%`}
                </div>
                <div className="stat-label">{s.label}</div>
              </div>
            ))}
          </div>

          {/* 3. Two-column: Confidence meters + Timeline */}
          <div style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: 16,
          }}>
            {/* Confidence Meters */}
            <div className="result-section">
              <h3 className="section-title">Confidence Meters</h3>
              <ConfidenceMeter
                label="Speaker Similarity"
                value={data.similarity}
                colorStart="#4361ee" colorEnd="#7b2ff7"
                delay={0}
              />
              <ConfidenceMeter
                label="Real Voice"
                value={data.real_prob}
                colorStart="#06d6a0" colorEnd="#059669"
                delay={120}
              />
              <ConfidenceMeter
                label="Deepfake Risk"
                value={data.fake_prob}
                colorStart="#f72585" colorEnd="#7b2ff7"
                delay={240}
              />
            </div>

            {/* Auth Timeline */}
            <div className="result-section">
              <h3 className="section-title">Authentication Steps</h3>
              <AuthTimeline granted={isGranted} isFake={isFake} />
            </div>
          </div>

          {/* 4. Spectrograms */}
          {(data.reg_spec || data.login_spec) && (
            <div className="result-section">
              <h3 className="section-title">Voice Spectrograms</h3>
              <div className="spec-grid">
                {data.reg_spec && (
                  <div className="spec-item">
                    <p className="spec-label">Registered Voice</p>
                    <img src={data.reg_spec} alt="Registered spectrogram" className="spec-img" />
                  </div>
                )}
                {data.login_spec && (
                  <div className="spec-item">
                    <p className="spec-label">Login Voice</p>
                    <img src={data.login_spec} alt="Login spectrogram" className="spec-img" />
                  </div>
                )}
              </div>
            </div>
          )}

          {/* 5. GradCAM */}
          {/* 6. LIME Explanation */}
          {data.lime_img && (
            <div className="result-section" style={{ borderColor: "rgba(123,47,247,0.2)" }}>
